        if (node.getNodeType() != Node.ELEMENT_NODE) {
            return false; // Only element nodes can be tested against NodeNameTest
        }

        NodeNameTest nodeNameTest = (NodeNameTest) test;
        QName testName = nodeNameTest.getNodeName();
        String namespaceURI = nodeNameTest.getNamespaceURI();
        boolean wildcard = nodeNameTest.isWildcard();
        String testPrefix = testName.getPrefix();

        if (wildcard && (testPrefix == null || testPrefix.isEmpty())) {
            return true; // Wildcard matches if no prefix is specified
        }

        // Check for name match
        if (wildcard || testName.getLocalPart().equals(DOMNodePointer.getLocalName(node))) {
            String nodeNS = DOMNodePointer.getNamespaceURI(node);
            return equalStrings(namespaceURI, nodeNS); // Compare namespace URIs
        }
        return false;
    }

    // Handle NodeTypeTest
    if (test instanceof NodeTypeTest) {
        int nodeType = node.getNodeType();
        int typeToTest = ((NodeTypeTest) test).getNodeType();

        switch (typeToTest) {
            case Compiler.NODE_TYPE_NODE:
                return nodeType == Node.ELEMENT_NODE || nodeType == Node.DOCUMENT_NODE;
            case Compiler.NODE_TYPE_TEXT:
                return nodeType == Node.CDATA_SECTION_NODE || nodeType == Node.TEXT_NODE;
            case Compiler.NODE_TYPE_COMMENT:
                return nodeType == Node.COMMENT_NODE;
            case Compiler.NODE_TYPE_PI:
                return nodeType == Node.PROCESSING_INSTRUCTION_NODE;
            default:
                return false; // Unknown node type test
        }
    }

